def count_nums(arr):
    count = 0
    for num in arr:
        digit_sum = 0
        if num < 0:
            # For negative numbers, first digit is negative
            num_str = str(num)[1:]  # Remove the '-' sign
            first_digit = -int(num_str[0])
            digit_sum = first_digit
            for digit in num_str[1:]:
                digit_sum += int(digit)
        else:
            # For positive numbers, sum all digits
            for digit in str(num):
                digit_sum += int(digit)

        if digit_sum > 0:
            count += 1

    return count
